import 'package:flutter/material.dart'; import 'package:flutter/services.dart'; import '../model/location_point.dart'; import '../../../core/theme/app_theme.dart'; class CoordinatesDisplay extends StatelessWidget { final LocationPoint location; const CoordinatesDisplay({super.key, required this.location}); @override Widget build(BuildContext context) => GestureDetector(onLongPress: () { Clipboard.setData(ClipboardData(text: location.formatted)); ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text('Coordinates copied'))); }, child: Container(padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8), decoration: BoxDecoration(color: AppTheme.darkCard, borderRadius: BorderRadius.circular(8)), child: Text(location.formatted, style: const TextStyle(color: AppTheme.primaryColor, fontSize: 12, fontFamily: 'monospace', fontWeight: FontWeight.w600)))); }